configs = model.search([('state', '=', 'connected')])
for config in configs:
    if config.sync_products:
        env['product.template'].shopify_import_all(config)
    if config.sync_customers:
        env['res.partner'].shopify_import_all(config)
    if config.sync_orders:
        env['sale.order'].shopify_import_all(config)
